+@page "/board"
+@using sv_c13a61ea5c9b4a38b26f82f71dce6cc2.Components.Board
+@inject ITaskService TaskService
+@rendermode InteractiveServer
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h3 class="mb-3">Kanban Board</h3>
+
+@if (isLoading)
+{
+    <div class="d-flex justify-content-center p-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @errorMessage
+        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStatsBar Tasks="allTasks" />
+    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />
+
+    <div class="row g-3">
+        @foreach (var column in columns)
+        {
+            var columnTasks = FilteredTasks
+                .Where(t => t.Status == column.Status)
+                .ToList();
+            var index = Array.IndexOf(columns, column);
+
+            <KanbanColumn Title="@column.Name"
+                          Status="@column.Status"
+                          Tasks="columnTasks"
+                          CanMoveLeft="index > 0"
+                          CanMoveRight="index < columns.Length - 1"
+                          OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, index)"
+                          OnTaskCreated="HandleTaskCreated" />
+        }
+    </div>
+}
+
+@code {
+    private List<TaskItem> allTasks = new();
+    private string searchText = "";
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    private static readonly (string Name, string Status)[] columns =
+    {
+        ("To Do", "To Do"),
+        ("In Progress", "In Progress"),
+        ("Done", "Done")
+    };
+
+    private IEnumerable<TaskItem> FilteredTasks =>
+        string.IsNullOrWhiteSpace(searchText)
+            ? allTasks
+            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void HandleSearchChanged(string value)
+    {
+        searchText = value;
+    }
+
+    private async Task HandleMoveTask(int taskId, KanbanColumn.MoveDirection direction, int currentColumnIndex)
+    {
+        var targetIndex = direction == KanbanColumn.MoveDirection.Left
+            ? currentColumnIndex - 1
+            : currentColumnIndex + 1;
+
+        if (targetIndex < 0 || targetIndex >= columns.Length) return;
+
+        var newStatus = columns[targetIndex].Status;
+        await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+
+        var task = allTasks.First(t => t.Id == taskId);
+        var index = allTasks.IndexOf(task);
+        allTasks[index] = task with { Status = newStatus };
+    }
+
+    private async Task HandleTaskCreated(TaskItem placeholder)
+    {
+        var created = await TaskService.CreateTaskAsync(
+            placeholder.Title, placeholder.Assignee, placeholder.Priority, placeholder.DueDate);
+        allTasks.Add(created);
+    }
+}
+

